using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Security.Claims;

namespace AzureFunctionWithLogging
{
    public static class DebugFunction
    {
        [FunctionName("DebugFunction")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
            ILogger log)
        {
            try
            {
                log.LogInformation("C# HTTP trigger function processed a request.");

                // Log request headers
                LogRequestHeaders(req, log);

                // Log request body
                string requestBody = await new StreamReader(req.Body).ReadToEndAsync();
                log.LogInformation($"Request Body: {requestBody}");

                // Log user context
                LogUserContext(req, log);

                // Process database query
                await ProcessDatabaseQuery(log, requestBody);

                return new OkObjectResult("Success");
            }
            catch (Exception ex)
            {
                log.LogError($"Exception occurred: {ex.Message}");
                log.LogError($"Exception StackTrace: {ex.StackTrace}");
                log.LogError($"Exception InnerException: {ex.InnerException?.Message}");
                log.LogError($"Exception Data: {JsonConvert.SerializeObject(ex.Data)}");
                return new StatusCodeResult(500);
            }
        }

        private static void LogRequestHeaders(HttpRequest req, ILogger log)
        {
            var headers = new Dictionary<string, string>();
            foreach (var header in req.Headers)
            {
                headers[header.Key] = header.Value.ToString();
            }
            log.LogInformation($"Request Headers: {JsonConvert.SerializeObject(headers)}");
        }

        private static void LogUserContext(HttpRequest req, ILogger log)
        {
            try
            {
                var claims = new List<string>();
                var authHeader = req.Headers["Authorization"].ToString();
                if (!string.IsNullOrEmpty(authHeader) && authHeader.StartsWith("Bearer "))
                {
                    var token = authHeader.Substring(7);
                    log.LogInformation($"Authentication Token: {token}");
                }

                var userId = req.Headers["X-User-ID"].ToString();
                if (!string.IsNullOrEmpty(userId))
                {
                    log.LogInformation($"User ID: {userId}");
                }

                var userEmail = req.Headers["X-User-Email"].ToString();
                if (!string.IsNullOrEmpty(userEmail))
                {
                    log.LogInformation($"User Email: {userEmail}");
                }
            }
            catch (Exception ex)
            {
                log.LogWarning($"Failed to log user context: {ex.Message}");
            }
        }

        private static async Task ProcessDatabaseQuery(ILogger log, string requestBody)
        {
            try
            {
                var queryData = JsonConvert.DeserializeObject<Dictionary<string, object>>(requestBody);
                var query = queryData["query"].ToString();
                var parameters = queryData["parameters"] as Dictionary<string, object>;

                log.LogInformation($"Database Query: {query}");

                if (parameters != null)
                {
                    var paramList = new List<string>();
                    foreach (var param in parameters)
                    {
                        paramList.Add($"{param.Key} = {param.Value}");
                    }
                    log.LogInformation($"Database Parameters: {string.Join(", ", paramList)}");
                }

                // Simulate database operation
                await Task.Delay(100);
                log.LogInformation("Database operation completed successfully");
            }
            catch (SqlException sqlEx)
            {
                log.LogError($"SQL Exception: {sqlEx.Message}");
                log.LogError($"SQL Error Number: {sqlEx.Number}");
                log.LogError($"SQL Procedure: {sqlEx.Procedure}");
                log.LogError($"SQL Line Number: {sqlEx.LineNumber}");
                throw;
            }
            catch (Exception ex)
            {
                log.LogError($"Database processing exception: {ex.Message}");
                throw;
            }
        }
    }
